        _cli = %cfg.omega__cli_path,
        _model = %_cli_model,
        smoke_test = cfg.is_smoke_test_profile(),
        "CLI-backed providers configured"
    );

    async fn build_memory_store(db_url: &str) -> anyhow::Result<Arc<dyn MemoryStore>> {
