                cfg.omega_claude_cli_path.clone(),
                cli_home.clone(),
                cfg.omega_cli_timeout_secs,
                Some(claude_model.clone()),
                claude_extra_args,
            )),
            Arc::new(LocalProvider::new(
                Some(cfg.omega_local_base_url.clone()),
                Some(cfg.omega_local_model.clone()),
            )),
        ]
    } else {
