            Arc::new(CliProvider::new(
                CliKind::Codex,
                cfg.omega_codex_cli_path.clone(),
                cli_home.clone(),
                cfg.omega_cli_timeout_secs,
                Some(codex_model.clone()),
                codex_extra_args.clone(),
            )),
