                cfg.omega_openai_api_key.clone(),
                cfg.omega_openai_base_url.clone(),
                cfg.omega_model.clone(),
            )),
            Arc::new(LocalProvider::new(
                Some(cfg.omega_local_base_url.clone()),
                Some(cfg.omega_local_model.clone()),
            )),
            Arc::new(Provider::new(
