    // Build a LocalProvider for SSE streaming.
    let local_for_stream: Arc<dyn omega_core::provider::LlmProvider> =
        Arc::new(LocalProvider::new(
            Some(cfg.omega_local_base_url.clone()),
            Some(cfg.omega_local_model.clone()),
        ));

